    19→import java.util.HashMap;
    20→import java.util.Map;
    21→
    22→import org.apache.camel.CamelContext;
    23→import org.apache.camel.SSLContextParametersAware;
    24→import org.apache.camel.component.kafka.consumer.KafkaManualCommit;
    25→import org.apache.camel.component.kafka.consumer.KafkaManualCommitFactory;
    26→import org.apache.camel.spi.Metadata;
    27→import org.apache.camel.spi.annotations.Component;
    28→import org.apache.camel.support.HealthCheckComponent;
    29→import org.apache.camel.support.PropertyBindingSupport;
    30→import org.apache.camel.util.ObjectHelper;
    31→import org.apache.camel.util.PropertiesHelper;
    32→import org.slf4j.Logger;
    33→import org.slf4j.LoggerFactory;
    34→
    35→@Component("kafka")
    36→public class KafkaComponent extends HealthCheckComponent implements SSLContextParametersAware {
    37→    private static final Logger LOG = LoggerFactory.getLogger(KafkaComponent.class);
    38→
    39→    @Metadata
    40→    private KafkaConfiguration configuration = new KafkaConfiguration();
    41→    @Metadata(label = "security", defaultValue = "false")
    42→    private boolean useGlobalSslContextParameters;
    43→    @Metadata(autowired = true, label = "consumer,advanced")
    44→    private KafkaManualCommitFactory kafkaManualCommitFactory;
    45→    @Metadata(autowired = true, label = "advanced")
    46→    private KafkaClientFactory kafkaClientFactory;
    47→    @Metadata(autowired = true, label = "consumer,advanced")
    48→    private PollExceptionStrategy pollExceptionStrategy;
    49→    @Metadata(label = "consumer,advanced")
    50→    private int createConsumerBackoffMaxAttempts;
    51→    @Metadata(label = "consumer,advanced", defaultValue = "5000")
    52→    private long createConsumerBackoffInterval = 5000;
    53→    @Metadata(label = "consumer,advanced")
    54→    private int subscribeConsumerBackoffMaxAttempts;
    55→    @Metadata(label = "consumer,advanced", defaultValue = "5000")
    56→    private long subscribeConsumerBackoffInterval = 5000;
    57→    @Metadata(label = "consumer,advanced")
    58→    private boolean subscribeConsumerTopicMustExists;
    59→
    60→    public KafkaComponent() {
    61→    }
    62→
    63→    public KafkaComponent(CamelContext context) {
    64→        super(context);
    65→    }
    66→
    67→    @Override
    68→    protected KafkaEndpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
    69→        if (ObjectHelper.isEmpty(remaining)) {
    70→            throw new IllegalArgumentException("Topic must be configured on endpoint using syntax kafka:topic");
    71→        }
    72→
    73→        // extract the endpoint additional properties map
    74→        final Map<String, Object> endpointAdditionalProperties
    75→                = PropertiesHelper.extractProperties(parameters, "additionalProperties.");
    76→
    77→        KafkaEndpoint endpoint = new KafkaEndpoint(uri, this);
    78→
    79→        KafkaConfiguration copy = getConfiguration().copy();
    80→        endpoint.setConfiguration(copy);
    81→
    82→        setProperties(endpoint, parameters);
    83→
    84→        if (endpoint.getConfiguration().getSslContextParameters() == null) {
    85→            endpoint.getConfiguration().setSslContextParameters(retrieveGlobalSslContextParameters());
    86→        }
    87→
    88→        if (!endpointAdditionalProperties.isEmpty()) {
    89→            Map<String, Object> map = new HashMap<>();
    90→            // resolve parameter values from the values (#bean / #class etc)
    91→            PropertyBindingSupport.bindProperties(getCamelContext(), map, endpointAdditionalProperties);
    92→            // overwrite the additional properties from the endpoint
    93→            endpoint.getConfiguration().getAdditionalProperties().putAll(map);
    94→        }
    95→
    96→        // If a topic is not defined in the KafkaConfiguration (set as option parameter) but only in the uri,
    97→        // it can happen that it is not set correctly in the configuration of the endpoint.
    98→        // Therefore, the topic is added after setProperties method
    99→        // and a null check to avoid overwriting a value from the configuration.
   100→        if (endpoint.getConfiguration().getTopic() == null) {
   101→            endpoint.getConfiguration().setTopic(remaining);
   102→        }
   103→
   104→        return endpoint;
   105→    }
