   107→    public KafkaConfiguration getConfiguration() {
   108→        return configuration;
   109→    }
   110→
   111→    /**
   112→     * Allows to pre-configure the Kafka component with common options that the endpoints will reuse.
   113→     */
   114→    public void setConfiguration(KafkaConfiguration configuration) {
   115→        this.configuration = configuration;
   116→    }
   117→
   118→    @Override
   119→    public boolean isUseGlobalSslContextParameters() {
   120→        return this.useGlobalSslContextParameters;
   121→    }
   122→
   123→    /**
   124→     * Enable usage of global SSL context parameters.
   125→     */
   126→    @Override
   127→    public void setUseGlobalSslContextParameters(boolean useGlobalSslContextParameters) {
   128→        this.useGlobalSslContextParameters = useGlobalSslContextParameters;
   129→    }
