   131→    public KafkaManualCommitFactory getKafkaManualCommitFactory() {
   132→        return kafkaManualCommitFactory;
   133→    }
   134→
   135→    /**
   136→     * Factory to use for creating {@link KafkaManualCommit} instances. This allows to plugin a custom factory to create
   137→     * custom {@link KafkaManualCommit} instances in case special logic is needed when doing manual commits that
   138→     * deviates from the default implementation that comes out of the box.
   139→     */
   140→    public void setKafkaManualCommitFactory(KafkaManualCommitFactory kafkaManualCommitFactory) {
   141→        this.kafkaManualCommitFactory = kafkaManualCommitFactory;
   142→    }
   143→
   144→    public KafkaClientFactory getKafkaClientFactory() {
   145→        return kafkaClientFactory;
   146→    }
   147→
   148→    /**
   149→     * Factory to use for creating {@link org.apache.kafka.clients.consumer.KafkaConsumer} and
   150→     * {@link org.apache.kafka.clients.producer.KafkaProducer} instances. This allows configuring a custom factory to
   151→     * create instances with logic that extends the vanilla Kafka clients.
   152→     */
   153→    public void setKafkaClientFactory(KafkaClientFactory kafkaClientFactory) {
   154→        this.kafkaClientFactory = kafkaClientFactory;
   155→    }
   156→
   157→    public PollExceptionStrategy getPollExceptionStrategy() {
   158→        return pollExceptionStrategy;
   159→    }
   160→
   161→    /**
   162→     * To use a custom strategy with the consumer to control how to handle exceptions thrown from the Kafka broker while
   163→     * pooling messages.
   164→     */
   165→    public void setPollExceptionStrategy(PollExceptionStrategy pollExceptionStrategy) {
   166→        this.pollExceptionStrategy = pollExceptionStrategy;
   167→    }
