import org.slf4j.LoggerFactory;

/**
 * FIX protocol consumer for receiving FIX messages.
 */
public class FixConsumer extends DefaultConsumer {
    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    private final FixEndpoint endpoint;
    private final FixConfiguration configuration;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
        this.endpoint = endpoint;
        this.configuration = endpoint.getConfiguration();
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.debug("FIX consumer started for session: {}", endpoint.getSessionID());

        // Initialize FIX acceptor/initiator session based on configuration
        if (configuration.getConfigFile() != null) {
            LOG.debug("Using FIX config file: {}", configuration.getConfigFile());
        }

        if (configuration.getSenderCompID() != null) {
            LOG.debug("FIX SenderCompID: {}", configuration.getSenderCompID());
        }

        if (configuration.getTargetCompID() != null) {
            LOG.debug("FIX TargetCompID: {}", configuration.getTargetCompID());
        }
    }

    @Override
    protected void doStop() throws Exception {
        super.doStop();
        LOG.debug("FIX consumer stopped for session: {}", endpoint.getSessionID());
    }
